import{_ as a,o as t,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"21. Regular Part Time Employment","description":"","frontmatter":{"title":"21. Regular Part Time Employment","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","employment","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/employment-types/21-regular-part-time-employment.md","filePath":"ebas/has-managers-admin/common-terms/employment-types/21-regular-part-time-employment.md"}'),n={name:"ebas/has-managers-admin/common-terms/employment-types/21-regular-part-time-employment.md"};function s(i,e,l,m,p,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_21-regular-part-time-employment" tabindex="-1">21. Regular Part Time Employment <a class="header-anchor" href="#_21-regular-part-time-employment" aria-label="Permalink to &quot;21. Regular Part Time Employment&quot;">​</a></h1><p><strong>21.1</strong> The Employer may employ regular part-time Employees in any classification covered by the Agreement.</p><p><strong>21.2</strong> A regular part-time Employee is one who:</p><p><strong>(a)</strong> works less than an average of the full-time hours per week (or fortnight);</p><p><strong>(b)</strong> has reasonably predictable hours of work; and</p><p><strong>(c)</strong> receives, on a pro-rata basis, equivalent pay and conditions to those of full-time Employees who do the same kind of work.</p><p><strong>21.3</strong> Before commencing employment, the Employer and regular part-time Employee will agree in writing on a regular pattern of work; including the :</p><p><strong>(a)</strong> number of hours to be worked each week;</p><p><strong>(b)</strong> days of the week the Employee will work; and,</p><p><strong>(c)</strong> starting and finishing times each day.</p><p><strong>21.4</strong> Any agreed variation to the regular pattern of work prescribed at subclause 21.3, including a variation as a result of an offer made pursuant to subclause 21.10(a), will be recorded in writing.</p><p><strong>21.5</strong> Regular part-time Employees will be paid 1/38th of the weekly wage rate for their classification pursuant to <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a> or <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a>. All leave entitlements will accrue on a pro-rata basis.</p><p><strong>21.6</strong> An Employee who does not meet the definition of a regular part-time Employee and who is not full-time will be paid as a casual Employee in accordance with <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/23-casual-employment.html">clause 23</a> (Casual Employment).</p><p><strong>21.7</strong> Payment in respect of any period of personal leave (where an Employee has an accumulated entitlement) will be made according to the ordinary hours the Employee would have worked on the day or days on which the leave was taken.</p><p><strong>21.8</strong> Any period of annual leave or personal leave will accrue according to the ordinary hours of work in accordance with the NES.</p><p><strong>21.9</strong> Notwithstanding the above, a part-time Employee who is employed on a regular basis for four hours or less per week will be paid according to clause 23 (Casual Employment).</p><p><strong>21.10</strong> Additional hours</p><p><strong>(a)</strong> A part time Employee may be offered additional hours at the applicable ordinary time rates for the time worked, within the limits prescribed by this Agreement.</p><p><strong>(b)</strong> A part-time Employee is entitled to decline an offer of additional ordinary hours.</p><p><strong>(c)</strong> Where a part-time Employee is directed by the Employer to work reasonable additional hours, or works hours in excess of 38 in a week, an average of 38 hours a week or the limits prescribed by the Agreement, overtime rates will apply.</p><p>Plain language terms: part-time, PT.</p>',21)])])}const c=a(n,[["render",s]]);export{h as __pageData,c as default};
